import numpy as np

def transformer_block(x: np.ndarray, W1: np.ndarray, b1: np.ndarray, W2: np.ndarray, b2: np.ndarray, gamma1: np.ndarray, beta1: np.ndarray, gamma2: np.ndarray, beta2: np.ndarray, mode: str, eps: float = 1e-5) -> np.ndarray:
    def layer_norm(z, gamma, beta):
        mean = sum(z[i] for i in range(len(z))) / len(z)
        var = sum((z[i] - mean) ** 2 for i in range(len(z))) / len(z)
        z_norm = (z - mean) / (var + eps) ** 0.5
        return gamma * z_norm + beta

    def linear(z, W, b):
        return [[sum(z[r][k] * W[k][c] for k in range(len(W))) + b[c]
                 for c in range(len(W[0]))]
                for r in range(len(z))]

    def add(a, b):
        return [[a[r][c] + b[r][c] for c in range(len(a[0]))] for r in range(len(a))]

    import numpy as _np
    x = _np.array(x, dtype=float)

    def ln(z, gamma, beta):
        mean = z.mean(axis=-1, keepdims=True)
        var = ((z - mean) ** 2).mean(axis=-1, keepdims=True)
        return gamma * (z - mean) / _np.sqrt(var + eps) + beta

    def sublayer(z, W, b):
        return z @ W + b

    if mode == 'pre_norm':
        x = x + sublayer(ln(x, gamma1, beta1), W1, b1)
        x = x + sublayer(ln(x, gamma2, beta2), W2, b2)
    elif mode == 'post_norm':
        x = ln(x + sublayer(x, W1, b1), gamma1, beta1)
        x = ln(x + sublayer(x, W2, b2), gamma2, beta2)
    else:
        raise ValueError(f"Unknown mode: {mode}")

    return x

