import numpy as np
import torch
import torch.nn.functional as F

def transformer_block(x: np.ndarray, W1: np.ndarray, b1: np.ndarray, W2: np.ndarray, b2: np.ndarray, gamma1: np.ndarray, beta1: np.ndarray, gamma2: np.ndarray, beta2: np.ndarray, mode: str, eps: float = 1e-5) -> np.ndarray:
    """
    Apply a transformer block using PyTorch ops.
    """
    to_t = lambda a: torch.tensor(np.array(a), dtype=torch.float32)
    x      = to_t(x)
    W1, b1 = to_t(W1), to_t(b1)
    W2, b2 = to_t(W2), to_t(b2)
    gamma1, beta1 = to_t(gamma1), to_t(beta1)
    gamma2, beta2 = to_t(gamma2), to_t(beta2)

    # normalized_shape = [d_model] — normalize over last dimension
    d_model = x.shape[-1]

    def layer_norm(z, gamma, beta):
        return F.layer_norm(z, normalized_shape=[d_model],
                            weight=gamma, bias=beta, eps=eps)

    def sublayer(z, W, b):
        return z @ W + b  # equivalent to F.linear(z, W.T, b)

    if mode == 'pre_norm':
        x = x + sublayer(layer_norm(x, gamma1, beta1), W1, b1)
        x = x + sublayer(layer_norm(x, gamma2, beta2), W2, b2)
    elif mode == 'post_norm':
        x = layer_norm(x + sublayer(x, W1, b1), gamma1, beta1)
        x = layer_norm(x + sublayer(x, W2, b2), gamma2, beta2)
    else:
        raise ValueError(f"Unknown mode: {mode}")

    return x.detach().numpy()
